/**
 * BSA §326 CIP gate (31 CFR §1020.220).
 *
 * Scenarios #6/#7 of guides/use-cases.md: an AccountHolder whose
 * kyc_status is not 'approved' may not originate any transaction,
 * regardless of amount or payment rail.
 *
 * Reads `debtor_payment_account.account_holder.kyc_status`. If the
 * status is anything other than 'approved' (in_progress, rejected,
 * expired, …), emits a blocked Control per LedgerAccount on the
 * debtor side. The cap=0 + is_blocked=true combination is what the
 * limits-at-entry check converts into status='rejected' with
 * rejected_rule='cip_kyc_not_approved'.
 */
export const handler = async (input) => {
  const debtor = input.debtor_payment_account;
  if (!debtor) return { ledger_accounts: {} };

  const kyc = debtor.account_holder && debtor.account_holder.kyc_status;
  if (kyc === 'approved') return { ledger_accounts: {} };

  const las = debtor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'cip_kyc_not_approved',
      block_reason: 'cip_kyc_not_approved',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
